def test_llm(provider, api_key=''):
    """测试大模型API连通性"""
    if not api_key:
        return '请先输入API Key'

    ep_info = LLM_ENDPOINTS.get(provider)
    model = LLM_MODELS.get(provider, 'model')

    if not ep_info:
        return '未知服务商'
    endpoint = ep_info['endpoint']

    try:
        if provider == 'claude':
            headers = {
                'x-api-key': api_key,
                'anthropic-version': '2023-06-01',
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'max_tokens': 10,
                'messages': [{'role': 'user', 'content': 'hi'}],
            }
        elif provider == 'zhipu':
            # 智谱GLM使用标准Bearer Token格式
            headers = {
                'Authorization': 'Bearer %s' % api_key,
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'messages': [{'role': 'user', 'content': 'hi'}],
                'max_tokens': 10,
                'stream': False,
            }
        else:
            headers = {
                'Authorization': 'Bearer %s' % api_key,
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'max_tokens': 10,
                'messages': [{'role': 'user', 'content': 'hi'}],
