package com.voicedoc.app;

import android.content.Intent;
import android.content.SharedPreferences;
import android.content.res.AssetManager;
import android.database.Cursor;
import android.media.MediaCodec;
import android.media.MediaExtractor;
import android.media.MediaFormat;
import android.net.Uri;
import android.os.Bundle;
import android.os.Environment;
import android.provider.DocumentsContract;
import android.provider.OpenableColumns;
import android.util.Log;
import android.view.View;
import android.widget.*;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.FileProvider;
import com.chaquo.python.PyObject;
import com.chaquo.python.Python;
import com.chaquo.python.android.AndroidPlatform;
import com.k2fsa.sherpa.onnx.*;

import java.io.*;
import java.nio.ByteBuffer;
import java.nio.ByteOrder;

public class MainActivity extends AppCompatActivity {
    private static final String TAG = "VoiceDocCompare";
    private TextView tvAudioName, tvDocName, tvStatus, tvResult, tvModelStatus;
    private ProgressBar progressBar;
    private Button btnCompare, btnTestModel, btnGenerateReport, btnShare;
    private Spinner spinnerAsrEngine;
    private ScrollView scrollResult;
    private String audioPath = "", docPath = "";
    private String lastAudioText = "", lastDocText = "", lastReportPath = "";
    private int selectedEngine = 0;
    private static final String PREFS_NAME = "voice_doc_prefs";
    private static final String GROQ_BUILTIN_KEY = "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";

    private static final String[] ENGINE_NAMES = {
        "离线识别(Sherpa-ONNX)", "FunASR(局域网)", "百度语音(内置)", "Groq Whisper", "OpenAI Whisper"
    };
    private static final String[] ENGINE_IDS = {
        "sherpa_offline", "funasr", "baidu_builtin", "groq_whisper", "openai_whisper"
    };

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        tvAudioName = findViewById(R.id.tvAudioName);
        tvDocName = findViewById(R.id.tvDocName);
        tvStatus = findViewById(R.id.tvStatus);
        tvResult = findViewById(R.id.tvResult);
        tvModelStatus = findViewById(R.id.tvModelStatus);
        progressBar = findViewById(R.id.progressBar);
        btnCompare = findViewById(R.id.btnCompare);
        btnTestModel = findViewById(R.id.btnTestModel);
        spinnerAsrEngine = findViewById(R.id.spinnerAsrEngine);
        scrollResult = findViewById(R.id.scrollResult);
        btnGenerateReport = findViewById(R.id.btnGenerateReport);
        btnShare = findViewById(R.id.btnShare);

        if (!Python.isStarted()) {
            Python.start(new AndroidPlatform(this));
        }

        ArrayAdapter<String> adapter = new ArrayAdapter<>(this,
            android.R.layout.simple_spinner_item, ENGINE_NAMES);
        adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        spinnerAsrEngine.setAdapter(adapter);
        spinnerAsrEngine.setOnItemSelectedListener(new AdapterView.OnItemSelectedListener() {
            @Override
            public void onItemSelected(AdapterView<?> parent, View view, int pos, long id) {
                selectedEngine = pos;
                checkModelStatus();
            }
            @Override
            public void onNothingSelected(AdapterView<?> parent) {}
        });

        findViewById(R.id.btnPickAudio).setOnClickListener(v -> pickFile("audio/*", 1));
        findViewById(R.id.btnPickDoc).setOnClickListener(v -> pickFile("application/*", 2));
        btnCompare.setOnClickListener(v -> startCompare());
        btnTestModel.setOnClickListener(v -> testModel());
        btnGenerateReport.setOnClickListener(v -> generateReport());
        btnShare.setOnClickListener(v -> shareReport());
        findViewById(R.id.btnSettings).setOnClickListener(v ->
            startActivity(new Intent(this, SettingsActivity.class)));

        loadSavedEngine();
        checkModelStatus();
        handleShareIntent(getIntent());
        autoSelectNewestFiles();
    }

    private void autoSelectNewestFiles() {
        // 自动选择Download/Weixin目录中最新的一对文件（音频+文档）
        new Thread(() -> {
            try {
                File downloadDir = new File(Environment.getExternalStorageDirectory(), "Download");
                File weixinDir = new File(downloadDir, "Weixin");
                File targetDir = weixinDir.exists() ? weixinDir : downloadDir;

                File[] files = targetDir.listFiles();
                if (files == null || files.length == 0) return;

                // 按修改时间排序，最新的在前
                java.util.Arrays.sort(files, (a, b) -> Long.compare(b.lastModified(), a.lastModified()));

                File newestAudio = null;
                File newestDoc = null;

                // 找最新的音频和文档
                for (File f : files) {
                    String name = f.getName().toLowerCase();
                    if (newestAudio == null && isAudioFile(name)) {
                        newestAudio = f;
                    } else if (newestDoc == null && isDocFile(name)) {
                        newestDoc = f;
                    }
                    if (newestAudio != null && newestDoc != null) break;
                }

                // 自动填充
                if (newestAudio != null) {
                    String path = newestAudio.getAbsolutePath();
                    audioPath = path;
                    final String name = newestAudio.getName();
                    runOnUiThread(() -> tvAudioName.setText(name));
                    Log.i(TAG, "自动选择音频: " + name);
                }
                if (newestDoc != null) {
                    String path = newestDoc.getAbsolutePath();
                    docPath = path;
                    final String name = newestDoc.getName();
                    runOnUiThread(() -> tvDocName.setText(name));
                    Log.i(TAG, "自动选择文档: " + name);
                }
            } catch (Exception e) {
                Log.e(TAG, "自动选择文件失败", e);
            }
        }).start();
    }

    private boolean isAudioFile(String name) {
        return name.endsWith(".wav") || name.endsWith(".mp3") || name.endsWith(".m4a") ||
               name.endsWith(".flac") || name.endsWith(".amr") || name.endsWith(".silk") ||
               name.endsWith(".ogg") || name.endsWith(".opus") || name.endsWith(".aac");
    }

    private boolean isDocFile(String name) {
        return name.endsWith(".docx") || name.endsWith(".doc") || name.endsWith(".txt");
    }

    @Override
    protected void onResume() {
        super.onResume();
        loadSavedEngine();
        checkModelStatus();
    }

    private void loadSavedEngine() {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        int saved = prefs.getInt("asr_engine", 0);
        if (saved >= 0 && saved < ENGINE_NAMES.length) {
            spinnerAsrEngine.setSelection(saved);
            selectedEngine = saved;
        }
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        handleShareIntent(intent);
    }

    private void handleShareIntent(Intent intent) {
        if (intent == null) return;
        String action = intent.getAction();
        if (Intent.ACTION_SEND.equals(action)) {
            Uri uri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
            if (uri != null) importFile(uri);
        }
    }

    private void checkModelStatus() {
        if (selectedEngine == 0) {
            try {
                getAssets().open("models/paraformer/model.int8.onnx").close();
                tvModelStatus.setText("离线模型: 已内置 (Paraformer 中英文)");
                tvModelStatus.setTextColor(0xFF4CAF50);
            } catch (IOException e) {
                tvModelStatus.setText("离线模型: 未找到，请重新安装APK");
                tvModelStatus.setTextColor(0xFFF44336);
            }
        } else if (selectedEngine == 1) {
            tvModelStatus.setText("FunASR: 需连接电脑上的FunASR服务 (同一WiFi)");
            tvModelStatus.setTextColor(0xFF1976D2);
        } else if (selectedEngine == 2) {
            tvModelStatus.setText("百度语音: 使用内置API密钥，需联网");
            tvModelStatus.setTextColor(0xFF4CAF50);
        } else if (selectedEngine == 3) {
            tvModelStatus.setText("Groq Whisper: 云端高速转写，需联网");
            tvModelStatus.setTextColor(0xFF1976D2);
        } else {
            tvModelStatus.setText("OpenAI Whisper: 云端高精度，需联网");
            tvModelStatus.setTextColor(0xFF1976D2);
        }
    }

    private void testModel() {
        btnTestModel.setEnabled(false);
        tvStatus.setText("正在测试...");
        new Thread(() -> {
            String result;
            try {
                if (selectedEngine == 0) {
                    getAssets().open("models/paraformer/model.int8.onnx").close();
                    getAssets().open("models/paraformer/tokens.txt").close();
                    result = "Sherpa-ONNX 离线模型就绪，无需网络";
                } else {
                    Python py = Python.getInstance();
                    PyObject engine = py.getModule("engine");
                    result = engine.callAttr("test_asr", ENGINE_IDS[selectedEngine], "").toString();
                }
            } catch (Exception e) {
                result = "测试失败: " + e.getMessage();
            }
            String finalResult = result;
            runOnUiThread(() -> {
                tvStatus.setText(finalResult);
                btnTestModel.setEnabled(true);
            });
        }).start();
    }

    private void pickFile(String mimeType, int requestCode) {
        Intent i = new Intent(Intent.ACTION_GET_CONTENT);
        i.setType(mimeType);
        i.addCategory(Intent.CATEGORY_OPENABLE);

        // 尝试设置默认路径为Download/Weixin
        try {
            // Android 7.0+ 使用Storage Access Framework
            if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
                // 尝试指向Download目录
                android.net.Uri downloadsUri = android.net.Uri.parse("content://com.android.externalstorage.documents/document/primary:Download");
                // 尝试指向Weixin子目录
                android.net.Uri weixinUri = android.net.Uri.parse("content://com.android.externalstorage.documents/document/primary:Download/Weixin");

                // 先尝试Weixin目录
                i.putExtra(DocumentsContract.EXTRA_INITIAL_URI, weixinUri.toString());
            }
        } catch (Exception e) {
            Log.w(TAG, "无法设置默认文件路径", e);
        }

        startActivityForResult(i, requestCode);
    }

    @Override
    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
        super.onActivityResult(requestCode, resultCode, data);
        if (resultCode != RESULT_OK || data == null) return;
        Uri uri = data.getData();
        if (uri == null) return;
        String path = copyToCache(uri);
        if (path == null) return;
        String name = getFileName(uri);
        if (requestCode == 1) {
            audioPath = path;
            tvAudioName.setText(name);
        } else {
            docPath = path;
            tvDocName.setText(name);
        }
    }

    private void importFile(Uri uri) {
        String path = copyToCache(uri);
        if (path == null) return;
        String name = getFileName(uri).toLowerCase();
        if (name.endsWith(".wav") || name.endsWith(".mp3") || name.endsWith(".m4a") ||
            name.endsWith(".flac") || name.endsWith(".amr") || name.endsWith(".silk") ||
            name.endsWith(".ogg") || name.endsWith(".opus") || name.endsWith(".aac")) {
            audioPath = path;
            tvAudioName.setText(getFileName(uri));
        } else {
            docPath = path;
            tvDocName.setText(getFileName(uri));
        }
        tvStatus.setText("已从微信导入文件");
    }

    private String copyToCache(Uri uri) {
        try {
            InputStream is = getContentResolver().openInputStream(uri);
            String name = getFileName(uri);
            File out = new File(getCacheDir(), name);
            FileOutputStream fos = new FileOutputStream(out);
            byte[] buf = new byte[8192];
            int n;
            while ((n = is.read(buf)) != -1) fos.write(buf, 0, n);
            fos.close();
            is.close();
            return out.getAbsolutePath();
        } catch (Exception e) {
            tvStatus.setText("文件导入失败: " + e.getMessage());
            return null;
        }
    }

    private String getFileName(Uri uri) {
        String name = "file";
        Cursor c = getContentResolver().query(uri, null, null, null, null);
        if (c != null && c.moveToFirst()) {
            int idx = c.getColumnIndex(OpenableColumns.DISPLAY_NAME);
            if (idx >= 0) name = c.getString(idx);
            c.close();
        }
        return name;
    }

    // ===== 音频解码：支持所有格式(WAV/MP3/M4A/FLAC/AMR/OGG...) =====
    private float[] decodeAudio(String filepath) throws Exception {
        MediaExtractor extractor = new MediaExtractor();
        extractor.setDataSource(filepath);

        // 查找音频轨道
        int trackIndex = -1;
        MediaFormat format = null;
        for (int i = 0; i < extractor.getTrackCount(); i++) {
            MediaFormat f = extractor.getTrackFormat(i);
            String mime = f.getString(MediaFormat.KEY_MIME);
            if (mime != null && mime.startsWith("audio/")) {
                trackIndex = i;
                format = f;
                break;
            }
        }
        if (trackIndex < 0) {
            throw new Exception("未找到音频轨道，文件可能不是音频格式");
        }

        extractor.selectTrack(trackIndex);
        String mime = format.getString(MediaFormat.KEY_MIME);
        int sampleRate = format.getInteger(MediaFormat.KEY_SAMPLE_RATE);
        int channels = format.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
        Log.i(TAG, "音频格式: " + mime + ", " + sampleRate + "Hz, " + channels + "ch");

        ByteArrayOutputStream pcmOut = new ByteArrayOutputStream();

        if ("audio/raw".equals(mime)) {
            // PCM WAV: 直接从extractor读取，不需要codec解码
            ByteBuffer buf = ByteBuffer.allocate(65536);
            while (extractor.readSampleData(buf, 0) >= 0) {
                int pos = buf.position();
                byte[] chunk = new byte[pos];
                buf.flip();
                buf.get(chunk);
                pcmOut.write(chunk);
                buf.clear();
                extractor.advance();
            }
        } else {
            // 压缩格式(MP3/AAC/FLAC/AMR等): 用MediaCodec解码
            MediaCodec codec = MediaCodec.createDecoderByType(mime);
            codec.configure(format, null, null, 0);
            codec.start();

            MediaCodec.BufferInfo info = new MediaCodec.BufferInfo();
            boolean inputDone = false;
            boolean outputDone = false;

            while (!outputDone) {
                // 送入压缩数据
                if (!inputDone) {
                    int inputIdx = codec.dequeueInputBuffer(10000);
                    if (inputIdx >= 0) {
                        ByteBuffer inputBuf = codec.getInputBuffer(inputIdx);
                        int size = extractor.readSampleData(inputBuf, 0);
                        if (size < 0) {
                            codec.queueInputBuffer(inputIdx, 0, 0, 0,
                                MediaCodec.BUFFER_FLAG_END_OF_STREAM);
                            inputDone = true;
                        } else {
                            codec.queueInputBuffer(inputIdx, 0, size,
                                extractor.getSampleTime(), 0);
                            extractor.advance();
                        }
                    }
                }

                // 取出PCM数据
                int outputIdx = codec.dequeueOutputBuffer(info, 10000);
                if (outputIdx >= 0) {
                    if ((info.flags & MediaCodec.BUFFER_FLAG_END_OF_STREAM) != 0) {
                        outputDone = true;
                    }
                    if (info.size > 0) {
                        ByteBuffer outputBuf = codec.getOutputBuffer(outputIdx);
                        byte[] chunk = new byte[info.size];
                        outputBuf.get(chunk);
                        pcmOut.write(chunk);
                    }
                    codec.releaseOutputBuffer(outputIdx, false);
                } else if (outputIdx == MediaCodec.INFO_OUTPUT_FORMAT_CHANGED) {
                    MediaFormat outFmt = codec.getOutputFormat();
                    sampleRate = outFmt.getInteger(MediaFormat.KEY_SAMPLE_RATE);
                    channels = outFmt.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
                    Log.i(TAG, "解码输出格式: " + sampleRate + "Hz, " + channels + "ch");
                }
            }

            codec.stop();
            codec.release();
        }

        extractor.release();

        byte[] pcmBytes = pcmOut.toByteArray();
        if (pcmBytes.length < 100) {
            throw new Exception("音频解码后数据为空 (原格式: " + mime + ")");
        }

        // PCM bytes -> float samples (16-bit little-endian)
        int numSamples = pcmBytes.length / 2;
        float[] allSamples = new float[numSamples];
        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
        for (int i = 0; i < numSamples; i++) {
            allSamples[i] = bb.getShort() / 32768.0f;
        }

        // 立体声 -> 单声道
        float[] mono;
        if (channels > 1) {
            int monoLen = numSamples / channels;
            mono = new float[monoLen];
            for (int i = 0; i < monoLen; i++) {
                float sum = 0;
                for (int c = 0; c < channels; c++) {
                    sum += allSamples[i * channels + c];
                }
                mono[i] = sum / channels;
            }
        } else {
            mono = allSamples;
        }

        // 重采样到16kHz
        if (sampleRate != 16000) {
            Log.i(TAG, "重采样: " + sampleRate + "Hz -> 16000Hz");
            mono = resample(mono, sampleRate, 16000);
        }

        float durationSec = mono.length / 16000.0f;
        Log.i(TAG, "解码完成: " + mono.length + " samples, " +
            String.format("%.1f", durationSec) + "s @ 16kHz mono");

        if (durationSec < 0.3f) {
            throw new Exception("音频太短 (" + String.format("%.1f", durationSec) + "秒)，无法识别");
        }

        return mono;
    }

    // ===== 线性插值重采样 =====
    private float[] resample(float[] input, int fromRate, int toRate) {
        double ratio = (double) fromRate / toRate;
        int outputLen = (int) (input.length / ratio);
        float[] output = new float[outputLen];
        for (int i = 0; i < outputLen; i++) {
            double srcIdx = i * ratio;
            int idx = (int) srcIdx;
            double frac = srcIdx - idx;
            if (idx + 1 < input.length) {
                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
            } else if (idx < input.length) {
                output[i] = input[idx];
            }
        }
        return output;
    }

    // ===== Sherpa-ONNX 离线识别（分段提升准确率） =====
    private String transcribeSherpa(String audioFile) throws Exception {
        // 解码音频为16kHz单声道（支持WAV/MP3/M4A/FLAC/AMR/OGG等）
        float[] samples = decodeAudio(audioFile);

        AssetManager assetManager = getAssets();

        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
        paraformerConfig.setModel("models/paraformer/model.int8.onnx");

        OfflineModelConfig modelConfig = new OfflineModelConfig();
        modelConfig.setParaformer(paraformerConfig);
        modelConfig.setTokens("models/paraformer/tokens.txt");
        modelConfig.setNumThreads(4);
        modelConfig.setDebug(false);

        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
        config.setModelConfig(modelConfig);
        config.setDecodingMethod("greedy_search");

        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);

        // 分段识别：每段30秒，提高长音频准确率
        int chunkSamples = 30 * 16000;
        int totalChunks = (int) Math.ceil((double) samples.length / chunkSamples);
        StringBuilder allText = new StringBuilder();

        if (totalChunks <= 1) {
            // 短音频直接识别
            OfflineStream stream = recognizer.createStream();
            stream.acceptWaveform(samples, 16000);
            recognizer.decode(stream);
            OfflineRecognizerResult result = recognizer.getResult(stream);
            allText.append(result.getText() != null ? result.getText().trim() : "");
            stream.release();
        } else {
            // 长音频分段识别
            for (int ci = 0; ci < totalChunks; ci++) {
                int finalCi = ci;
                runOnUiThread(() -> tvStatus.setText(
                    String.format("离线识别 %d/%d...", finalCi + 1, totalChunks)));

                int start = ci * chunkSamples;
                // 加1秒重叠避免截断
                int overlap = ci > 0 ? 16000 : 0;
                int actualStart = Math.max(0, start - overlap);
                int end = Math.min(samples.length, start + chunkSamples);
                int len = end - actualStart;

                if (len < 1600) continue; // 不足0.1秒跳过

                float[] chunk = new float[len];
                System.arraycopy(samples, actualStart, chunk, 0, len);

                OfflineStream stream = recognizer.createStream();
                stream.acceptWaveform(chunk, 16000);
                recognizer.decode(stream);
                OfflineRecognizerResult result = recognizer.getResult(stream);
                String text = result.getText() != null ? result.getText().trim() : "";

                if (!text.isEmpty()) {
                    // 去除重叠部分导致的重复（最长公共后缀/前缀匹配，窗口30字）
                    if (ci > 0 && allText.length() > 0 && overlap > 0) {
                        String prev = allText.toString();
                        int maxCheck = Math.min(30, Math.min(prev.length(), text.length()));
                        int bestMatch = 0;
                        for (int t = maxCheck; t > 0; t--) {
                            if (prev.endsWith(text.substring(0, t))) {
                                bestMatch = t;
                                break;
                            }
                        }
                        if (bestMatch > 0) {
                            text = text.substring(bestMatch);
                        }
                    }
                    allText.append(text);
                }
                stream.release();
            }
        }

        recognizer.release();
        return allText.toString().trim();
    }

    // ===== 开始对比 =====
    private void startCompare() {
        if (audioPath.isEmpty() || docPath.isEmpty()) {
            tvStatus.setText("请先选择录音和文档");
            return;
        }
        btnCompare.setEnabled(false);
        progressBar.setVisibility(View.VISIBLE);
        tvStatus.setText("正在处理...");

        new Thread(() -> {
            try {
                String audioText;

                if (selectedEngine == 0) {
                    runOnUiThread(() -> tvStatus.setText("正在解码音频..."));
                    audioText = transcribeSherpa(audioPath);
                } else {
                    // 其他引擎: 调用Python转录，传递API密钥
                    String engineId = ENGINE_IDS[selectedEngine];
                    runOnUiThread(() -> tvStatus.setText(
                        "正在识别（" + ENGINE_NAMES[selectedEngine] + "）..."));

                    SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
                    String extraArg = "";
                    if ("funasr".equals(engineId)) {
                        extraArg = prefs.getString("funasr_server", "http://192.168.1.100:8765");
                    } else if ("groq_whisper".equals(engineId)) {
                        extraArg = prefs.getString("groq_key", GROQ_BUILTIN_KEY);
                    } else if ("openai_whisper".equals(engineId)) {
                        extraArg = prefs.getString("openai_key", "");
                    }

                    Python py = Python.getInstance();
                    PyObject engine = py.getModule("engine");
                    audioText = engine.callAttr("transcribe", audioPath, engineId, extraArg).toString();
                }

                Log.i(TAG, "ASR结果: " + audioText);

                if (audioText.isEmpty()) {
                    runOnUiThread(() -> {
                        tvStatus.setText("语音识别结果为空，请检查音频是否有语音内容");
                        progressBar.setVisibility(View.GONE);
                        btnCompare.setEnabled(true);
                    });
                    return;
                }

                runOnUiThread(() -> tvStatus.setText("正在对比文本..."));
                Python py = Python.getInstance();
                PyObject engine = py.getModule("engine");
                PyObject result = engine.callAttr("run_compare", audioText, docPath);

                String summary = result.callAttr("get", "summary").toString();
                String details = result.callAttr("get", "details").toString();

                // 保存结果供报告生成使用
                lastAudioText = audioText;
                lastReportPath = "";

                runOnUiThread(() -> {
                    tvStatus.setText("对比完成");
                    tvResult.setText(summary + "\n\n" + details);
                    scrollResult.setVisibility(View.VISIBLE);
                    progressBar.setVisibility(View.GONE);
                    btnCompare.setEnabled(true);
                    // 显示报告按钮
                    if (btnGenerateReport != null) btnGenerateReport.setVisibility(View.VISIBLE);
                    if (btnShare != null) btnShare.setVisibility(View.VISIBLE);
                });
            } catch (Exception e) {
                Log.e(TAG, "处理失败", e);
                String errMsg = e.getMessage();
                if (errMsg == null) errMsg = e.getClass().getSimpleName();
                String finalErr = errMsg;
                runOnUiThread(() -> {
                    tvStatus.setText("错误: " + finalErr);
                    progressBar.setVisibility(View.GONE);
                    btnCompare.setEnabled(true);
                });
            }
        }).start();
    }

    // ===== 生成Word报告 =====
    private void generateReport() {
        if (lastAudioText.isEmpty()) {
            tvStatus.setText("请先执行对比");
            return;
        }
        tvStatus.setText("正在生成报告...");
        new Thread(() -> {
            try {
                Python py = Python.getInstance();
                PyObject engine = py.getModule("engine");
                String resultText = tvResult.getText().toString();
                PyObject reportPath = engine.callAttr("generate_report_txt",
                    audioPath, docPath, lastAudioText, resultText);
                lastReportPath = reportPath.toString();
                runOnUiThread(() -> tvStatus.setText("报告已保存: " + lastReportPath));
            } catch (Exception e) {
                Log.e(TAG, "报告生成失败", e);
                runOnUiThread(() -> tvStatus.setText("报告生成失败: " + e.getMessage()));
            }
        }).start();
    }

    // ===== 分享报告 =====
    private void shareReport() {
        if (lastReportPath.isEmpty()) {
            // 先生成再分享
            generateReport();
            return;
        }
        try {
            File file = new File(lastReportPath);
            if (!file.exists()) {
                tvStatus.setText("报告文件不存在");
                return;
            }
            Uri uri = FileProvider.getUriForFile(
                this, getPackageName() + ".fileprovider", file);
            Intent intent = new Intent(Intent.ACTION_SEND);
            String mimeType = lastReportPath.endsWith(".docx")
                ? "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                : "text/plain";
            intent.setType(mimeType);
            intent.putExtra(Intent.EXTRA_STREAM, uri);
            intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);
            startActivity(Intent.createChooser(intent, "分享核对报告"));
        } catch (Exception e) {
            tvStatus.setText("分享失败: " + e.getMessage());
        }
    }
}

